from mcp.server import Server
from mcp import types
import asyncio, os, requests

app = Server("github-tools-server")
_TOKEN = os.environ["GITHUB_TOKEN"]
_BASE = "https://api.github.com"
_HDR = {"Authorization": f"Bearer {_TOKEN}"}

@app.list_tools()
async def list_tools() -> list[types.Tool]:
    return [
        types.Tool(
            name="list_issues",
            description="List open issues for a GitHub repository.",
            inputSchema={
                "type": "object",
                "properties": {
                    "owner": {"type": "string", "description": "Repository owner"},
                    "repo":  {"type": "string", "description": "Repository name"},
                    "labels": {"type": "string", "description": "Comma-separated label filter (optional)"},
                },
                "required": ["owner", "repo"],
            },
        ),
        types.Tool(
            name="close_issue",
            description="Close a GitHub issue by number.",
            inputSchema={
                "type": "object",
                "properties": {
                    "owner":        {"type": "string"},
                    "repo":         {"type": "string"},
                    "issue_number": {"type": "integer", "description": "Issue number to close"},
                    "comment":      {"type": "string",  "description": "Optional closing comment"},
                },
                "required": ["owner", "repo", "issue_number"],
            },
        ),
    ]

@app.call_tool()
async def call_tool(name: str, arguments: dict) -> list[types.TextContent]:
    if name == "list_issues":
        params = {"state": "open", "per_page": 20}
        if arguments.get("labels"):
            params["labels"] = arguments["labels"]
        resp = requests.get(
            f"{_BASE}/repos/{arguments['owner']}/{arguments['repo']}/issues",
            params=params, headers=_HDR, timeout=10,
        )
        resp.raise_for_status()
        issues = resp.json()
        lines = [f"#{i['number']}: {i['title']} [{', '.join(l['name'] for l in i['labels'])}]"
                 for i in issues]
        return [types.TextContent(type="text", text="\n".join(lines) or "No issues.")]

    if name == "close_issue":
        owner, repo, num = arguments["owner"], arguments["repo"], arguments["issue_number"]
        if arguments.get("comment"):
            requests.post(
                f"{_BASE}/repos/{owner}/{repo}/issues/{num}/comments",
                json={"body": arguments["comment"]}, headers=_HDR, timeout=10,
            ).raise_for_status()
        resp = requests.patch(
            f"{_BASE}/repos/{owner}/{repo}/issues/{num}",
            json={"state": "closed"}, headers=_HDR, timeout=10,
        )
        resp.raise_for_status()
        return [types.TextContent(type="text", text=f"Closed issue #{num}.")]

    raise ValueError(f"Unknown tool: {name}")
